+        if (memBytes >= 1024 * 1024) {
+          memorySize = `${(memBytes / 1024 / 1024).toFixed(1)} MB`;
+        } else if (memBytes >= 1024) {
+          memorySize = `${(memBytes / 1024).toFixed(1)} KB`;
+        } else {
+          memorySize = `${memBytes} B`;
+        }
+      }
+    } catch { /* cache not initialized */ }
+
